  font-size: 0.8rem;
  font-weight: 600;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--vp-c-brand-1);
  margin: 0 0 1rem;
}

.lp-title {
  font-family: var(--vp-font-family-display);
  font-size: clamp(2.4rem, 5.2vw, 4rem);
  line-height: 1.05;
  letter-spacing: -0.03em;
  font-weight: 800;
  margin: 0;
  color: var(--vp-c-text-1);
}

.lp-grad {
  background: linear-gradient(120deg, #0ea5e9, #6d28d9 92%);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
  color: transparent;
}
.dark .lp-grad {
  background: linear-gradient(120deg, #7dd3fc, #c084fc 92%);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
}

.lp-lede {
  margin: 1.5rem 0 0;
  max-width: 34rem;
  font-size: 1.12rem;
  line-height: 1.65;
  color: var(--vp-c-text-2);
}
.lp-lede strong {
  color: var(--vp-c-text-1);
}

.lp-cta {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  margin-top: 2rem;
}

.btn {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.7rem 1.4rem;
  border-radius: 999px;
  font-weight: 600;
  font-size: 0.97rem;
  transition:
    transform 0.2s ease,
    box-shadow 0.2s ease,
    background-color 0.2s ease,
    border-color 0.2s ease;
}
.btn-primary {
  color: #fff;
  background: linear-gradient(120deg, #0ea5e9, #0369a1);
  box-shadow: 0 10px 24px -10px rgba(2, 132, 199, 0.7);
}
.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 16px 30px -12px rgba(2, 132, 199, 0.8);
}
.btn-arrow {
  transition: transform 0.2s ease;
}
.btn-primary:hover .btn-arrow {
  transform: translateX(3px);
}
.btn-ghost {
  color: var(--vp-c-text-1);
  background: var(--vp-c-bg-soft);
  border: 1px solid var(--vp-c-divider);
}
.btn-ghost:hover {
  border-color: var(--vp-c-brand-1);
  color: var(--vp-c-brand-1);
  transform: translateY(-2px);
}

.lp-install {
  margin-top: 1.8rem;
  display: inline-flex;
  flex-direction: column;
  max-width: 100%;
  border-radius: 12px;
  border: 1px solid var(--vp-c-divider);
  background: var(--vp-c-bg-soft);
  overflow: clip;
}
.lp-install-tabs {
  display: flex;
  overflow-x: auto;
  scrollbar-width: none;
  border-bottom: 1px solid var(--vp-c-divider);
}
.lp-install-tabs::-webkit-scrollbar {
  display: none;
}
.lp-tab {
  flex: 0 0 auto;
  padding: 0.42rem 0.95rem;
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--vp-c-text-2);
  border-bottom: 2px solid transparent;
  transition:
    color 0.2s ease,
    border-color 0.2s ease,
    background-color 0.2s ease;
}
.lp-tab:hover {
  color: var(--vp-c-text-1);
}
.lp-tab.active {
  color: var(--vp-c-brand-1);
  border-bottom-color: var(--vp-c-brand-1);
  background: var(--vp-c-bg);
}
.lp-install-cmd {
  display: flex;
  align-items: center;
  gap: 0.55rem;
  padding: 0.7rem 0.9rem;
  font-family: var(--vp-font-family-mono);
  font-size: 0.85rem;
}
.lp-install-cmd .prompt {
  color: var(--vp-c-brand-1);
  user-select: none;
}
.lp-install-cmd code {
  padding: 0;
  background: none;
  color: var(--vp-c-text-1);
  white-space: nowrap;
}
.lp-copy {
  margin-left: auto;
  padding: 0.18rem 0.55rem;
  font-size: 0.72rem;
  font-weight: 600;
  font-family: var(--vp-font-family-base);
  border-radius: 6px;
  color: var(--vp-c-text-2);
  border: 1px solid var(--vp-c-divider);
  transition:
    color 0.2s ease,
    border-color 0.2s ease;
}
.lp-copy:hover {
  color: var(--vp-c-brand-1);
  border-color: var(--vp-c-brand-1);
}

.lp-runtimes {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 0.4rem 1.2rem;
  margin-top: 1.5rem;
  font-size: 0.85rem;
}
.lp-runtimes-label {
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  color: var(--vp-c-text-2);
  opacity: 0.7;
}
.lp-runtimes .rt {
  display: inline-flex;
  align-items: center;
  gap: 0.42rem;
  font-weight: 600;
  color: var(--vp-c-text-2);
  transition: color 0.2s ease;
}
.lp-runtimes .rt:hover {
  color: var(--vp-c-text-1);
}
.lp-runtimes .rt-logo {
  display: inline-flex;
}
.lp-runtimes .rt-logo :deep(svg) {
  width: 18px;
  height: 18px;
}

/* Hero artwork: federated network around the logo. */
.lp-hero-art {
  position: relative;
  justify-self: center;
  width: min(440px, 92%);
  aspect-ratio: 1;
}
.lp-net {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  overflow: visible;
}
.lp-net .rings circle {
  fill: none;
  stroke: var(--vp-c-brand-1);
  stroke-opacity: 0.18;
  stroke-dasharray: 3 7;
}
.lp-net .orbit line {
  stroke: var(--vp-c-brand-1);
  stroke-opacity: 0.3;
  stroke-width: 1.4;
  stroke-dasharray: 4 6;
}
.lp-net .node {
  stroke: var(--vp-c-bg);
  stroke-width: 3;
}
.lp-net .n1 { fill: #00a3ff; }
.lp-net .n2 { fill: #0ea5e9; }
.lp-net .n3 { fill: #9500ff; }
.lp-net .n4 { fill: #ffca00; }
.lp-net .n5 { fill: #38bdf8; }
.lp-net-logo {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 38%;
  transform: translate(-50%, -50%);
  filter: drop-shadow(0 12px 30px rgba(2, 132, 199, 0.35));
}

/* --------------------------- Sections -------------------------- */
.lp-section {
  padding: 5.5rem 0;
}
.lp-section-alt {
  background: var(--vp-c-bg-soft);
  border-block: 1px solid var(--vp-c-divider);
}
.lp-narrow {
  max-width: 760px;
}
.lp-kicker {
  font-size: 0.8rem;
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--vp-c-brand-1);
  margin: 0 0 0.9rem;
}
.lp-h2 {
  font-family: var(--vp-font-family-display);
  font-size: clamp(1.7rem, 3.2vw, 2.4rem);
  line-height: 1.18;
  letter-spacing: -0.02em;
  font-weight: 800;
  margin: 0;
  color: var(--vp-c-text-1);
}
.lp-body {
  margin: 1.2rem 0 0;
  font-size: 1.06rem;
  line-height: 1.7;
  color: var(--vp-c-text-2);
}
.lp-textlink {
  display: inline-block;
  margin-top: 1.4rem;
  font-weight: 600;
  color: var(--vp-c-brand-1);
}
.lp-textlink:hover {
  color: var(--vp-c-brand-2);
}
.lp-section-head {
  text-align: center;
  max-width: 680px;
  margin: 0 auto 2.5rem;
}

/* ----------------------------- Why ----------------------------- */
.lp-why {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 3rem;
  align-items: center;
}
.lp-stack {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  gap: 0.6rem;
}
.lp-stack li {
  position: relative;
  display: flex;
  align-items: center;
  gap: 0.8rem;
  padding: 0.8rem 1.1rem;
  border-radius: 12px;
  background: var(--vp-c-bg);
  border: 1px solid var(--vp-c-divider);
  font-weight: 600;
  color: var(--vp-c-text-1);
  transition:
    border-color 0.2s ease,
    color 0.2s ease;
}
.lp-stack-name {
  color: inherit;
  text-decoration: none;
}
.lp-stack-spec {
  font-family: var(--vp-font-family-mono);
  font-size: 0.72rem;
  font-weight: 500;
  color: var(--vp-c-text-3, var(--vp-c-text-2));
  white-space: nowrap;
}
/* Make the whole row clickable for linked specs. */
a.lp-stack-name::after {
  content: "";
  position: absolute;
  inset: 0;
}
.lp-stack-go {
  margin-left: auto;
  font-weight: 700;
  color: var(--vp-c-brand-1);
  opacity: 0;
  transform: translateX(-4px);
  transition:
    opacity 0.2s ease,
    transform 0.2s ease;
}
.lp-stack li.has-link:hover {
  border-color: var(--vp-c-brand-1);
  color: var(--vp-c-brand-1);
}
.lp-stack li.has-link:hover .lp-stack-go {
  opacity: 1;
  transform: translateX(0);
}
/* Topical icon chip on the left of each spec (sky-tinted, brand-colored). */
.lp-stack-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  flex: none;
  border-radius: 10px;
  color: var(--vp-c-brand-1);
  background: linear-gradient(135deg, var(--vp-c-brand-soft), transparent);
  border: 1px solid rgba(2, 132, 199, 0.18);
}
.dark .lp-stack-icon {
  border-color: rgba(56, 189, 248, 0.22);
}
.lp-stack-logo {
  display: inline-flex;
}
.lp-stack-icon :deep(svg) {
  width: 20px;
  height: 20px;
}

/* ------------------------- Code showcase ----------------------- */
.lp-code-grid {
  display: grid;
  grid-template-columns: 0.9fr 1.1fr;
  gap: 3rem;
  align-items: center;
}
.lp-code-window {
  border-radius: 14px;
  overflow: clip;
  background: #0b1622;
  border: 1px solid #1e3a52;
  box-shadow: 0 30px 60px -30px rgba(2, 132, 199, 0.5);
}
.lp-code-bar {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.7rem 1rem;
  background: #0d1b2a;
  border-bottom: 1px solid #1e3a52;
}
.lp-code-bar .dot {
  width: 11px;
  height: 11px;
  border-radius: 50%;
  background: #1e3a52;
}
.lp-code-bar .dot:nth-child(1) { background: #f87171; }
.lp-code-bar .dot:nth-child(2) { background: #fbbf24; }
.lp-code-bar .dot:nth-child(3) { background: #34d399; }
.lp-code-file {
  margin-left: 0.6rem;
  font-family: var(--vp-font-family-mono);
  font-size: 0.8rem;
  color: #7c93a8;
}
.lp-code {
  margin: 0;
  padding: 1.25rem 1.4rem;
  overflow-x: auto;
  font-family: var(--vp-font-family-mono);
  font-size: 0.82rem;
  line-height: 1.7;
  color: #cbd5e1;
}
.lp-code :deep(.c-kw) { color: #7dd3fc; }
.lp-code :deep(.c-st) { color: #86efac; }
.lp-code :deep(.c-ty) { color: #fcd34d; }
.lp-code :deep(.c-fn) { color: #93c5fd; }
.lp-code :deep(.c-cm) { color: #64748b; font-style: italic; }

/* ----------------------- Framework section --------------------- */
.lp-byo {
  display: grid;
  grid-template-columns: 1fr 1.1fr;
  gap: 2.5rem;
  align-items: center;
  max-width: 960px;
  margin: 5.5rem auto 0;
  padding: 2rem;
  border-radius: 16px;
  background: var(--vp-c-bg);
  border: 1px solid var(--vp-c-divider);
}
.lp-byo-title {
  font-family: var(--vp-font-family-display);
  font-size: 1.3rem;
  font-weight: 700;
  letter-spacing: -0.01em;
  margin: 0;
  color: var(--vp-c-text-1);
}
.lp-byo-text {
  margin: 0.8rem 0 0;
  font-size: 1rem;
  line-height: 1.65;
  color: var(--vp-c-text-2);
}
.lp-byo-text code {
  font-family: var(--vp-font-family-mono);
  font-size: 0.85em;
  padding: 0.1em 0.4em;
  border-radius: 5px;
  background: var(--vp-c-brand-soft);
  color: var(--vp-c-brand-1);
}
.lp-byo-text a {
  text-decoration: none;
}
.lp-byo-text a:hover code {
  text-decoration: underline;
}
.lp-byo-window {
  margin: 0;
}

/* --------------------- Reliable delivery ----------------------- */
.lp-points {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.25rem;
}
.lp-point {
  padding: 1.5rem;
  border-radius: 16px;
  background: var(--vp-c-bg);
  border: 1px solid var(--vp-c-divider);
}
.lp-point-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 42px;
  height: 42px;
  border-radius: 11px;
  color: var(--vp-c-brand-1);
  background: linear-gradient(135deg, var(--vp-c-brand-soft), transparent);
  border: 1px solid rgba(2, 132, 199, 0.18);
}
.dark .lp-point-icon {
  border-color: rgba(56, 189, 248, 0.22);
}
.lp-point-title {
  font-family: var(--vp-font-family-display);
  font-size: 1.1rem;
  font-weight: 700;
  letter-spacing: -0.01em;
  margin: 1rem 0 0.45rem;
  color: var(--vp-c-text-1);
}
.lp-point-desc {
  margin: 0;
  font-size: 0.94rem;
  line-height: 1.6;
  color: var(--vp-c-text-2);
}
.lp-brokers-label {
  margin: 3.5rem 0 0;
  text-align: center;
  font-size: 0.78rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  color: var(--vp-c-text-2);
  opacity: 0.7;
}

/* --------------------------- Observability --------------------- */
.lp-otel {
  display: grid;
  grid-template-columns: 1fr 1.05fr;
  gap: 3rem;
  align-items: center;
}
.lp-otel-list {
  list-style: none;
  margin: 1.6rem 0 0;
  padding: 0;
  display: grid;
  gap: 1rem;
}
.lp-otel-list li {
  display: flex;
  gap: 0.75rem;
  align-items: flex-start;
}
.lp-otel-ic {
  flex: none;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  margin-top: 1px;
  border-radius: 7px;
  color: #fff;
  background: linear-gradient(135deg, #0ea5e9, #0369a1);
}
.lp-otel-ic svg {
  width: 14px;
  height: 14px;
}
.lp-otel-text {
  font-size: 1rem;
  line-height: 1.55;
}
.lp-otel-term {
  display: block;
  font-weight: 600;
  color: var(--vp-c-text-1);
}
.lp-otel-desc {
  display: block;
  color: var(--vp-c-text-2);
}

/* Trace-waterfall mock. */
.lp-trace {
  border-radius: 14px;
  overflow: clip;
  background: var(--vp-c-bg);
  border: 1px solid var(--vp-c-divider);
  box-shadow: 0 24px 50px -28px rgba(2, 132, 199, 0.45);
}
.lp-trace-bar {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.7rem 1rem;
  background: var(--vp-c-bg-soft);
  border-bottom: 1px solid var(--vp-c-divider);
}
.lp-trace-bar .dot {
  width: 11px;
  height: 11px;
  border-radius: 50%;
  background: var(--vp-c-divider);
}
.lp-trace-bar .dot:nth-child(1) { background: #f87171; }
.lp-trace-bar .dot:nth-child(2) { background: #fbbf24; }
.lp-trace-bar .dot:nth-child(3) { background: #34d399; }
.lp-trace-title {
  margin-left: 0.6rem;
  font-family: var(--vp-font-family-mono);
  font-size: 0.8rem;
  color: var(--vp-c-text-2);
}
.lp-trace-body {
  padding: 1.25rem 1.4rem;
  display: grid;
  gap: 0.85rem;
}
.lp-trace-label {
  display: block;
  margin-bottom: 5px;
  font-family: var(--vp-font-family-mono);
  font-size: 0.76rem;
  color: var(--vp-c-text-2);
}
.lp-trace-track {
  display: block;
  position: relative;
  height: 9px;
  border-radius: 999px;
  background: var(--vp-c-bg-soft);
}
.lp-trace-span {
  position: absolute;
  top: 0;
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, #38bdf8, #0369a1);
}

/* ---------------------------- Interop -------------------------- */
.lp-interop {
  text-align: center;
}
.lp-interop .lp-kicker,
.lp-interop .lp-h2 {
  text-align: center;
}
.lp-logos {
  list-style: none;
  margin: 2.6rem 0 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: center;
  gap: 1.5rem 2.4rem;
}
.lp-logo {
  display: inline-flex;
  align-items: center;
  color: var(--vp-c-text-2);
  text-decoration: none;
  opacity: 0.65;
  transition:
    color 0.2s ease,
    opacity 0.2s ease;
}
.lp-logo:hover {
  color: var(--vp-c-text-1);
  opacity: 1;
}
.lp-logo-svg {
  display: inline-flex;
}
.lp-logo-svg :deep(svg) {
  height: 30px;
  width: auto;
  display: block;
}
/* Logos shipped as files are tinted to currentColor via a CSS mask so they
   adapt to light/dark like the inline ones. */
.lp-logo--mask {
  width: 30px;
  height: 30px;
  background-color: currentColor;
  -webkit-mask: var(--mask) center / contain no-repeat;
  mask: var(--mask) center / contain no-repeat;
}
.lp-logo-more {
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--vp-c-text-2);
  opacity: 0.65;
}

/* --------------------------- Final CTA ------------------------- */
.lp-cta-band {
  position: relative;
  padding: 6rem 0;
  text-align: center;
  overflow: clip;
  border-top: 1px solid var(--vp-c-divider);
}
.lp-cta-bg {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
}
.lp-cta-bg .orb-cyan {
  width: 50vw;
  max-width: 680px;
  aspect-ratio: 1;
  left: 50%;
  top: -30%;
  transform: translateX(-50%);
  background: radial-gradient(circle, #0ea5e9 0%, transparent 68%);
  opacity: 0.18;
}
.lp-cta-bg .orb-violet {
  width: 30vw;
  max-width: 420px;
  aspect-ratio: 1;
  right: 8%;
  bottom: -20%;
  background: radial-gradient(circle, #9500ff 0%, transparent 70%);
  opacity: 0.16;
}
.lp-cta-inner {
  position: relative;
  z-index: 1;
}
.lp-cta-title {
  font-family: var(--vp-font-family-display);
  font-size: clamp(1.9rem, 4vw, 2.8rem);
  font-weight: 800;
  letter-spacing: -0.02em;
  margin: 0;
  color: var(--vp-c-text-1);
}
.lp-cta-sub {
  margin: 1rem auto 0;
  max-width: 36rem;
  font-size: 1.08rem;
  color: var(--vp-c-text-2);
}
.lp-cta-band .lp-cta {
  justify-content: center;
}
.lp-sponsors {
  margin-top: 2.2rem;
  font-size: 0.92rem;
  color: var(--vp-c-text-2);
}
.lp-sponsors a {
  color: var(--vp-c-brand-1);
  font-weight: 600;
}

/* --------------------------- Animation ------------------------- */
@media (prefers-reduced-motion: no-preference) {
  .lp-hero-copy > * {
    animation: lp-rise 0.7s cubic-bezier(0.22, 1, 0.36, 1) both;
  }
  .lp-eyebrow { animation-delay: 0.02s; }
  .lp-title { animation-delay: 0.1s; }
  .lp-lede { animation-delay: 0.2s; }
  .lp-cta { animation-delay: 0.3s; }
  .lp-install { animation-delay: 0.4s; }
  .lp-runtimes { animation-delay: 0.5s; }
  .lp-hero-art {
    animation: lp-pop 1s cubic-bezier(0.22, 1, 0.36, 1) both;
    animation-delay: 0.15s;
  }
  /* Rotate the whole <svg> element (a compositor-friendly HTML element) rather
     than an inner <g>.  Firefox does not GPU-composite transforms on SVG
     sub-elements, so rotating <g> re-rasterized the SVG every frame and
     stuttered; promoting the SVG to its own layer lets the rotation run on the
     GPU.  Keeping it the only animation on this layer means it rasterizes once. */
  .lp-net {
    transform-origin: 50% 50%;
    will-change: transform;
    animation: lp-spin 70s linear infinite;
  }
  .lp-stack li {
    animation: lp-rise 0.5s cubic-bezier(0.22, 1, 0.36, 1) both;
    animation-delay: calc(var(--i) * 60ms);
  }
}

@keyframes lp-rise {
  from { opacity: 0; transform: translateY(16px); }
  to { opacity: 1; transform: none; }
}
@keyframes lp-pop {
  from { opacity: 0; transform: scale(0.92); }
  to { opacity: 1; transform: none; }
}
@keyframes lp-spin {
  to { transform: rotate(360deg); }
}

/* --------------------------- Responsive ------------------------ */
@media (max-width: 900px) {
  .lp-hero-grid,
  .lp-why,
